INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1850, 207030, 5, 2169, '真爱无敌', '这样的天气 似乎让没个人都变得郁闷 心事重重 思绪绵绵 心里却异常烦躁 我并不是那种想不开的人 可今晚有种发泄的冲动 很晚了 一个人慢慢地走到阿俊家 他正在打电话 是玲 液晶显示已经49分钟了 他讲得特别开心 似乎没注意到我的到来 他们在讲他爸妈出差后她来为他煮饭 烧菜的事 她是个好女孩 单纯 善良 俊把话筒让给了我 我不知该讲些什么 随便讲了几句 又让了回去 他们讲了几分钟 直到液晶显示1小时12分50秒时才结束 我们在一起坐了很久 看了两集电视剧 剧情了的男男女女分分合合我不喜欢 于是拉他去网吧打发时间从网吧出来已经是12点多了 我们谁都不想回家 在大街上闲逛 讲着我们的烦心事 不知不觉的来到了金鑫广场 四周零零星星的恋人正在甜言蜜语 而两个男生走在一起显得有点…… 我找了个好地方坐下继续着我们的谈话 话题始终离不开感情 他的女朋友是洁 洁是个做是从不考虑后果比较小器的人 当初俊和她在一起的时候 我们都劝过他 你们不合适的 你应该找个好女孩 可最后他们还是在一起了 俊是真的喜欢她 可是他也喜欢玲 俊和洁已经一个星期没联系了 俊说他很想她 我只好微微笑着 我又何尝不是 连唯一可以联络的方式电话也不通了 我还能怎么样 至少他比我好 洁还是他的女朋友 而我和娅 什么都不是 俊说好想在她们之间选一个爱到底 我说 俊 选玲吧 她是个好女孩 她对你真的很好 她才会给你真正的爱 俊沉默着 她换了个坐姿 擦了擦脸 我知道他舍不得洁 而我感觉他更喜欢玲 我说现在的男人都怎么了 都喜欢玩二选一 很辛苦的 特别是洁这样小器的女孩 因为一点小事已经一个星期没联系了 我劝俊 放手吧 不值得 我知道他心里想的是什么 他需要的并不是有人帮他做出决定 而是有个人支持他在心里的决心 我还是习惯的唱着哥歌 心里却很难受 自己的事都搞不定 怎么帮别人嘛 回来的时候已经两点多了 我却被这莫明的思绪搅得特别清醒 朋友说不要太在意 就算一起也未必幸福 嗳 现在的我只想唱自己的歌 我相信 ture love is unbreakable  我相信 真爱无敌', '这样的天气 似乎让没个人都变得郁闷 心事重重 思绪绵绵 心里却异常烦躁 我并不是那种想不开的人 可今晚有种发泄的冲动 很晚了 一个人慢慢地走到阿俊家 他正在打电话 是玲 液晶显示已经49分钟了 他讲得特别开心 似乎没注意到我的到来 他们在讲他爸妈出差后她来为他煮饭 烧菜的事 她是个好女孩 单纯 善良 俊把话筒让给了我 我不知该讲些什么 随便讲了几句 又让了回去 他们讲了几分钟 直到液晶显示1小时12分50秒时才结束 我们在一起坐了很久 看了两集电视剧 剧情了的男男女女分分合合我不喜欢 于是拉他去网吧打发时间从网吧出来已经是12点多了 我们谁都不想回家 在大街上闲逛 讲着我们的烦心事 不知不觉的来到了金鑫广场 四周零零星星的恋人正在甜言蜜语 而两个男生走在一起显得有点…… 我找了个好地方坐下继续着我们的谈话 话题始终离不开感情 他的女朋友是洁 洁是个做是从不考虑后果比较小器的人 当初俊和她在一起的时候 我们都劝过他 你们不合适的 你应该找个好女孩 可最后他们还是在一起了 俊是真的喜欢她 可是他也喜欢玲 俊和洁已经一个星期没联系了 俊说他很想她 我只好微微笑着 我又何尝不是 连唯一可以联络的方式电话也不通了 我还能怎么样 至少他比我好 洁还是他的女朋友 而我和娅 什么都不是 俊说好想在她们之间选一个爱到底 我说 俊 选玲吧 她是个好女孩 她对你真的很好 她才会给你真正的爱 俊沉默着 她换了个坐姿 擦了擦脸 我知道他舍不得洁 而我感觉他更喜欢玲 我说现在的男人都怎么了 都喜欢玩二选一 很辛苦的 特别是洁这样小器的女孩 因为一点小事已经一个星期没联系了 我劝俊 放手吧 不值得 我知道他心里想的是什么 他需要的并不是有人帮他做出决定 而是有个人支持他在心里的决心 我还是习惯的唱着哥歌 心里却很难受 自己的事都搞不定 怎么帮别人嘛 回来的时候已经两点多了 我却被这莫明的思绪搅得特别清醒 朋友说不要太在意 就算一起也未必幸福 嗳 现在的我只想唱自己的歌 我相信 ture love is unbreakable  我相信 真爱无敌', '时间会淡去一切，也会证明一切……', '2003-07-01 23:13:00', 2, '2003071914162